    93→/// Helper struct for scanning player objects for auto heal
    94→pub struct AutoHealPlayerScanHelper {
    95→    pub kind_of_to_test: KindOfMaskType,
    96→    pub forbidden_kind_of: KindOfMaskType,
    97→    pub the_healer: Option<Arc<RwLock<Object>>>,
    98→    pub object_list: Vec<Arc<RwLock<Object>>>,
    99→    pub skip_self_for_healing: Bool,
   100→}
   101→
   102→impl AutoHealPlayerScanHelper {
   103→    pub fn new() -> Self {
   104→        Self {
   105→            kind_of_to_test: KindOfMaskType::all(),
   106→            forbidden_kind_of: KindOfMaskType::none(),
   107→            the_healer: None,
   108→            object_list: Vec::new(),
   109→            skip_self_for_healing: false,
   110→        }
   111→    }
   112→
   113→    /// Check if an object should be auto-healed
   114→    pub fn check_for_auto_heal(&mut self, test_obj: Arc<RwLock<Object>>) -> Result<(), Box<dyn std::error::Error>> {
   115→        let test_obj_read = test_obj.read()?;
   116→        
   117→        if test_obj_read.is_effectively_dead() {
   118→            return Ok(());
   119→        }
   120→
   121→        if let (Some(healer), Some(controlling_player)) = (&self.the_healer, test_obj_read.get_controlling_player()) {
   122→            let healer_read = healer.read()?;
   123→            if let Some(healer_player) = healer_read.get_controlling_player() {
   124→                if !Arc::ptr_eq(&controlling_player, &healer_player) {
   125→                    return Ok(());
   126→                }
   127→            }
   128→        }
   129→
   130→        if test_obj_read.is_off_map() {
   131→            return Ok(());
   132→        }
   133→
   134→        if self.skip_self_for_healing {
   135→            if let Some(healer) = &self.the_healer {
   136→                if Arc::ptr_eq(&test_obj, healer) {
   137→                    return Ok(());
   138→                }
   139→            }
   140→        }
   141→
   142→        if !test_obj_read.is_any_kind_of(&self.kind_of_to_test) {
   143→            return Ok(());
   144→        }
   145→
   146→        if test_obj_read.is_any_kind_of(&self.forbidden_kind_of) {
   147→            return Ok(());
   148→        }
   149→
   150→        if let Some(body) = test_obj_read.get_body_module() {
   151→            let body_lock = body.lock()?;
   152→            if body_lock.get_health() >= body_lock.get_max_health() {
   153→                return Ok(());
   154→            }
   155→        }
   156→
   157→        self.object_list.push(test_obj.clone());
   158→        Ok(())
   159→    }
   160→}
