   162→/// AutoHealBehavior - Main implementation of auto-healing behavior
   163→pub struct AutoHealBehavior {
   164→    pub base: UpdateModule,
   165→    pub thing: Arc<RwLock<dyn Thing>>,
   166→    pub module_data: Arc<AutoHealBehaviorModuleData>,
   167→    
   168→    // Particle system for radius effect
   169→    pub radius_particle_system_id: ParticleSystemID,
   170→    
   171→    // Timing and state
   172→    pub soonest_heal_frame: UnsignedInt,
   173→    pub stopped: Bool,
   174→    
   175→    // Upgrade system
   176→    pub upgrade_executed: Bool,
   177→}
   178→
   179→impl AutoHealBehavior {
   180→    pub fn new(
   181→        thing: Arc<RwLock<dyn Thing>>,
   182→        module_data: Arc<AutoHealBehaviorModuleData>,
   183→    ) -> Result<Self, Box<dyn std::error::Error>> {
   184→        let mut auto_heal = Self {
   185→            base: UpdateModule::new(thing.clone(), module_data.base.clone())?,
   186→            thing: thing.clone(),
   187→            module_data: module_data.clone(),
   188→            radius_particle_system_id: INVALID_PARTICLE_SYSTEM_ID,
   189→            soonest_heal_frame: 0,
   190→            stopped: false,
   191→            upgrade_executed: false,
   192→        };
   193→        
   194→        // Create radius particle system if specified
   195→        if let Some(radius_particle_tmpl) = &module_data.radius_particle_system_tmpl {
   196→            // In a real implementation, we'd create the particle system here
   197→            // auto_heal.radius_particle_system_id = create_particle_system(radius_particle_tmpl)?;
   198→        }
   199→        
   200→        // If initially active, give self upgrade and randomize wake timing
   201→        if module_data.initially_active {
   202→            auto_heal.give_self_upgrade();
   203→            
   204→            // Start with random phasing to avoid all units checking on same frame
   205→            let delay = module_data.healing_delay;
   206→            if delay > 0 {
   207→                let random_delay = (delay as f32 * rand::random::<f32>()) as UnsignedInt + 1;
   208→                auto_heal.set_wake_frame(UPDATE_SLEEP_TIME(random_delay));
   209→            }
   210→        } else {
   211→            auto_heal.set_wake_frame(UPDATE_SLEEP_FOREVER);
   212→        }
   213→        
   214→        Ok(auto_heal)
   215→    }
   216→    
   217→    /// Stop healing behavior
   218→    pub fn stop_healing(&mut self) {
   219→        self.stopped = true;
   220→        self.soonest_heal_frame = NEVER;
   221→        self.set_wake_frame(UPDATE_SLEEP_FOREVER);
   222→    }
   223→    
   224→    /// Undo upgrade - reset to non-upgraded state
   225→    pub fn undo_upgrade(&mut self) {
   226→        self.soonest_heal_frame = 0;
   227→        self.upgrade_executed = false;
   228→    }
   229→    
   230→    /// Check if upgrade is currently active
   231→    pub fn is_upgrade_active(&self) -> Bool {
   232→        self.upgrade_executed
   233→    }
   234→    
   235→    /// Give self the upgrade (activate healing)
   236→    pub fn give_self_upgrade(&mut self) {
   237→        self.upgrade_executed = true;
   238→        self.set_wake_frame(UPDATE_SLEEP_NONE);
   239→    }
   240→    
   241→    /// Pulse heal a single object
   242→    pub fn pulse_heal_object(&mut self, obj: Arc<RwLock<Object>>) -> Result<(), Box<dyn std::error::Error>> {
   243→        if self.stopped {
   244→            return Ok(());
   245→        }
   246→        
   247→        let data = &self.module_data;
   248→        
   249→        // Attempt healing - different logic for radius vs non-radius
   250→        if data.radius == 0.0 {
   251→            if let Ok(mut obj_write) = obj.write() {
   252→                obj_write.attempt_healing(data.healing_amount as Real, self.get_object())?;
   253→            }
   254→        } else {
   255→            if let Ok(mut obj_write) = obj.write() {
   256→                obj_write.attempt_healing_from_sole_benefactor(
   257→                    data.healing_amount as Real,
   258→                    self.get_object(),
   259→                    data.healing_delay,
   260→                )?;
   261→            }
   262→        }
   263→        
   264→        // Create heal pulse particle effect
   265→        if let Some(pulse_particle_tmpl) = &data.unit_heal_pulse_particle_system_tmpl {
   266→            // In a real implementation, we'd create the particle system here
   267→            // create_particle_system_at_position(pulse_particle_tmpl, obj.get_position())?;
   268→        }
   269→        
   270→        // Update soonest heal frame
   271→        if let Ok(current_frame) = self.get_current_frame() {
   272→            self.soonest_heal_frame = current_frame + data.healing_delay;
   273→        }
   274→        
   275→        Ok(())
   276→    }
