   296→// Implement DamageModuleInterface for handling damage events
   297→impl DamageModuleInterface for AutoHealBehavior {
   298→    fn on_damage(&mut self, damage_info: &mut DamageInfo) -> Result<(), Box<dyn std::error::Error>> {
   299→        if self.stopped {
   300→            return Ok(());
   301→        }
   302→        
   303→        let data = &self.module_data;
   304→        if self.is_upgrade_active() && data.radius == 0.0 {
   305→            // If we have a start healing delay, getting damaged resets our healing process
   306→            if data.start_healing_delay > 0 {
   307→                self.set_wake_frame(UPDATE_SLEEP_TIME(data.start_healing_delay));
   308→            } else {
   309→                // Check if we can wake up immediately
   310→                if let Ok(current_frame) = self.get_current_frame() {
   311→                    if current_frame > self.soonest_heal_frame {
   312→                        self.set_wake_frame(UPDATE_SLEEP_NONE);
   313→                    }
   314→                }
   315→            }
   316→        }
   317→        
   318→        Ok(())
   319→    }
