   337→// Implement UpdateModule for main update loop
   338→impl UpdateModule for AutoHealBehavior {
   339→    fn update(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   340→        if self.stopped {
   341→            return Ok(UPDATE_SLEEP_FOREVER);
   342→        }
   343→        
   344→        let obj = match self.get_object() {
   345→            Some(obj) => obj,
   346→            None => return Ok(UPDATE_SLEEP_FOREVER),
   347→        };
   348→        
   349→        let data = &self.module_data;
   350→        
   351→        // Don't heal if not upgraded or if effectively dead
   352→        if !self.is_upgrade_active() {
   353→            return Ok(UPDATE_SLEEP_FOREVER);
   354→        }
   355→        
   356→        if let Ok(obj_read) = obj.read() {
   357→            if obj_read.is_effectively_dead() {
   358→                return Ok(UPDATE_SLEEP_FOREVER);
   359→            }
   360→        }
   361→        
   362→        if data.affects_whole_player {
   363→            // Heal all objects belonging to the same player
   364→            self.heal_all_player_objects()?;
   365→            Ok(UPDATE_SLEEP_TIME(data.healing_delay))
   366→        } else if data.radius == 0.0 {
   367→            // Original system - heal self only
   368→            self.heal_self_only()?
   369→        } else {
   370→            // Expanded system - heal friendlies in radius
   371→            self.heal_friendlies_in_radius()?
   372→        }
   373→    }
   374→    
   375→    fn get_disabled_types_to_process(&self) -> DisabledMaskType {
   376→        DisabledMaskType::new() // Return mask for DISABLED_HELD
   377→    }
   378→}
