   380→impl AutoHealBehavior {
   381→    /// Heal all objects belonging to the same player
   382→    fn heal_all_player_objects(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   383→        let data = &self.module_data;
   384→        let obj = match self.get_object() {
   385→            Some(obj) => obj,
   386→            None => return Ok(UPDATE_SLEEP_FOREVER),
   387→        };
   388→        
   389→        let controlling_player = {
   390→            let obj_read = obj.read()?;
   391→            obj_read.get_controlling_player()
   392→        };
   393→        
   394→        if let Some(player) = controlling_player {
   395→            let mut helper = AutoHealPlayerScanHelper::new();
   396→            helper.kind_of_to_test = data.kind_of.clone();
   397→            helper.forbidden_kind_of = data.forbidden_kind_of.clone();
   398→            helper.the_healer = Some(obj.clone());
   399→            helper.skip_self_for_healing = data.skip_self_for_healing;
   400→            
   401→            // Iterate through all player objects
   402→            // In real implementation: player.iterate_objects(check_for_auto_heal, &mut helper)?;
   403→            
   404→            // Heal all qualifying objects
   405→            for heal_obj in helper.object_list {
   406→                self.pulse_heal_object(heal_obj)?;
   407→            }
   408→        }
   409→        
   410→        Ok(UPDATE_SLEEP_TIME(data.healing_delay))
   411→    }
   412→    
   413→    /// Heal self only (original system)
   414→    fn heal_self_only(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   415→        let data = &self.module_data;
   416→        let obj = match self.get_object() {
   417→            Some(obj) => obj,
   418→            None => return Ok(UPDATE_SLEEP_FOREVER),
   419→        };
   420→        
   421→        // Check if we need healing
   422→        let needs_healing = {
   423→            let obj_read = obj.read()?;
   424→            if let Some(body) = obj_read.get_body_module() {
   425→                let body_lock = body.lock()?;
   426→                body_lock.get_health() < body_lock.get_max_health()
   427→            } else {
   428→                false
   429→            }
   430→        };
   431→        
   432→        if needs_healing {
   433→            self.pulse_heal_object(obj)?;
   434→            Ok(UPDATE_SLEEP_TIME(data.healing_delay))
   435→        } else {
   436→            // Go to sleep forever - we'll wake up when damaged again
   437→            Ok(UPDATE_SLEEP_FOREVER)
   438→        }
   439→    }
   440→    
   441→    /// Heal friendlies in radius (expanded system)
   442→    fn heal_friendlies_in_radius(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   443→        let data = &self.module_data;
   444→        let obj = match self.get_object() {
   445→            Some(obj) => obj,
   446→            None => return Ok(UPDATE_SLEEP_FOREVER),
   447→        };
   448→        
   449→        // In real implementation, we would:
   450→        // 1. Set up partition filters for allies, alive, same map status
   451→        // 2. Scan objects in radius using partition manager
   452→        // 3. For each qualifying object, check health and kind restrictions
   453→        // 4. Pulse heal qualifying objects
   454→        // 5. Show heal effects if single burst mode
   455→        
   456→        let sleep_time = if data.single_burst {
   457→            UPDATE_SLEEP_FOREVER
   458→        } else {
   459→            UPDATE_SLEEP_TIME(data.healing_delay)
   460→        };
   461→        
   462→        Ok(sleep_time)
   463→    }
   464→}
