   112→    /// Handle object death - distinguishes between real death and fake slow death
   113→    pub fn on_die(&mut self, damage_info: &DamageInfo) -> Result<(), Box<dyn std::error::Error>> {
   114→        // Set flag beforehand because onDie could result in picking us to beginSlowDeath
   115→        self.is_real_death = true;
   116→        self.is_in_first_death = false;  // Clear this in case we died while in alternate death
   117→        
   118→        // Call base implementation
   119→        self.base.on_die(damage_info)
