   121→    
   122→    /// Begin slow death sequence - can do fake death before real one
   123→    pub fn begin_slow_death(&mut self, damage_info: &DamageInfo) -> Result<(), Box<dyn std::error::Error>> {
   124→        let me = self.get_object()?;
   125→        let data = &self.module_data;
   126→        
   127→        if !self.is_real_death {
   128→            // We can intercept and do our extra slow death if this is not from a real onDie
   129→            self.is_in_first_death = true;
   130→            self.ground_check_frame = self.get_current_frame()? + GROUND_CHECK_DELAY;
   131→            
   132→            // Damage passengers
   133→            if data.percent_damage_to_passengers > 0.0 {
   134→                self.damage_passengers(data.percent_damage_to_passengers)?;
   135→            }
   136→            
   137→            // Apply throw force to make the bus go flying
   138→            if data.throw_force > 0.0 {
   139→                self.apply_throw_force(data.throw_force)?;
   140→            }
   141→            
   142→            // Execute start undeath FX
   143→            if let Some(fx) = &data.fx_start_undeath {
   144→                self.execute_fx_at_object(fx.clone(), me.clone())?;
   145→            }
   146→            
   147→            // Execute start undeath OCL
   148→            if let Some(ocl) = &data.ocl_start_undeath {
   149→                self.execute_ocl_at_object(ocl.clone(), me.clone())?;
   150→            }
   151→            
   152→            // Set penalty death frame if empty hulk destruction delay is specified
   153→            if data.empty_hulk_destruction_delay > 0 {
   154→                self.penalty_death_frame = self.get_current_frame()? + data.empty_hulk_destruction_delay;
   155→            }
   156→        } else {
   157→            // This is a real death, call base implementation
   158→            self.base.begin_slow_death(damage_info)?;
   159→        }
   160→        
   161→        Ok(())
   162→    }
   163→    
   164→    /// Update method - handles the slow death sequence
   165→    pub fn update(&mut self) -> Result<UpdateSleepTime, Box<dyn std::error::Error>> {
   166→        if self.is_real_death && !self.is_in_first_death {
   167→            // Regular slow death behavior
   168→            return self.base.update();
   169→        }
   170→        
   171→        if self.is_in_first_death {
   172→            let current_frame = self.get_current_frame()?;
   173→            let me = self.get_object()?;
   174→            let data = &self.module_data;
   175→            
   176→            // Check if we should kill empty hulk
   177→            if self.penalty_death_frame > 0 && current_frame >= self.penalty_death_frame {
   178→                // Check if we're empty every EMPTY_HULK_CHECK_DELAY frames
   179→                if current_frame % EMPTY_HULK_CHECK_DELAY == 0 {
   180→                    if self.is_contain_empty()? {
   181→                        // Kill with penalty damage
   182→                        self.kill_with_penalty_damage()?;
   183→                        return Ok(crate::modules::UPDATE_SLEEP_FOREVER);
   184→                    }
   185→                }
   186→            }
   187→            
   188→            // Check for ground collision
   189→            if current_frame >= self.ground_check_frame {
   190→                if self.has_hit_ground()? {
   191→                    // We've hit the ground, execute hit ground effects
   192→                    if let Some(fx) = &data.fx_hit_ground {
   193→                        self.execute_fx_at_object(fx.clone(), me.clone())?;
   194→                    }
   195→                    
   196→                    if let Some(ocl) = &data.ocl_hit_ground {
   197→                        self.execute_ocl_at_object(ocl.clone(), me.clone())?;
   198→                    }
   199→                    
   200→                    // Transition to real death
   201→                    self.is_in_first_death = false;
   202→                    self.is_real_death = true;
   203→                    
   204→                    // Begin real slow death
   205→                    let damage_info = self.create_penalty_damage_info()?;
   206→                    self.base.begin_slow_death(&damage_info)?;
   207→                }
   208→            }
   209→            
   210→            // Continue updating
   211→            return Ok(1);  // Wake up next frame
   212→        }
   213→        
   214→        // Default case - call base implementation
   215→        self.base.update()
   216→    }
